VALUES
  ('elementary-0a2fc18c-moex-00903', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '依行政程序法規定，下列何者不屬於比例原則之內涵？', '["行政行為應有法律之依據", "行政行為應有助於行政目的之達成", "若有多種行政行為均同樣能達成行政目的，行政機關應選擇對人民權益損害最少者", "行政行為所造成之損害不得與欲達成行政目的之利益顯失均衡"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00904', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '有關瑕疵行政處分效力之敘述，下列何者正確？', '["無效行政處分，不發生救濟可能性；得撤銷之行政處分得由人民訴請行政法院撤銷", "行政處分違反公共秩序善良風俗者，無效", "無效行政處分，係自發現無效事由時起，向將來失效；得撤銷行政處分經撤銷後，有溯及失效的效果", "行政機關作成瑕疵行政處分，不得本於職權撤銷該處分，僅得由行政法院為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00905', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何種行政處分之瑕疵，依行政程序法規定得以補正？', '["應經人民申請而未經申請之行政處分", "由行政處分書面不能得知處分機關之行政處分", "相對人不存在之行政處分", "違反專屬管轄之行政處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00906', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '徵收人民土地應同時給與人民相當於市價之金錢彌補，該金錢給與之法律性質為何？', '["國家賠償", "損失補償", "損害賠償", "準徵收之侵害"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00907', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列何者之爭議，不得向行政法院尋求救濟？', '["甲在市立公園遊玩，因設施鏽蝕導致受傷，請求國家賠償", "乙不服市政府對其申請自用房屋適用優惠稅率之否准決定", "丙不服市政府對其所為之罰鍰處分", "丁不服市政府所為之專案考績免職處分"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00908', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '提起下列何種行政訴訟類型，原則上應先踐行訴願程序？', '["一般給付訴訟", "行政處分無效確認訴訟", "課予義務訴訟", "法律關係存否確認訴訟"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00909', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '行政訴訟若以公法人之機關為被告，原則上應由那一個行政法院管轄？', '["由被告機關所在地之行政法院管轄", "由原告戶籍所在地之行政法院管轄", "由原告住所地之行政法院管轄", "一律以中央政府所在地之行政法院管轄"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00910', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '甲死亡後留下數筆存款及土地，其子女乙、丙、丁、戊為繼承人。甲遺囑中表示四大房子孫要團結，故 不得分割遺產。下列敘述何者正確？', '["乙、丙、丁、戊不能分割，要傳給後代變成祭祀公業", "乙為繼承人，得隨時請求分割遺產，丙、丁、戊不得拒絕", "乙、丙、丁、戊不能分割，但繼承開始10年後，得請求分割遺產", "乙、丙、丁、戊於甲死後，因遺囑禁止分割，依民法規定，遺產於20年內均不得分割"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00911', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '下列關於民事訴訟代理人之敘述，何者正確？', '["簡易事件第二審之訴訟代理人，應委任具有教育部認證之法律相關科系獲碩士學位以上者，擔任訴訟 代理人。該訴訟代理人之酬金，由國庫墊之", "訴訟代理人就其受委任之事件有為一切訴訟行為之權。但捨棄、認諾、撤回、和解、提起反訴、上訴 或再審之訴及選任代理人，非受特別委任不得為之", "訴訟代理人有二人以上者，應共同代理當事人，不得單獨為之", "訴訟代理人為當事人聲請訴之追加、變更或提起反訴時，應先以書面聲請法院得審判長同意後，並為 當事人先墊付訴訟費用"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL),
  ('elementary-0a2fc18c-moex-00912', 'elementary-0a2fc18c', 'elementary-0a2fc18c-moex-110-55d283b0', 'sub-elementary-0a2fc18c-03', NULL, 'single_choice', '關於自治條例之敘述，下列何者錯誤？', '["應分別冠以各該地方自治團體之名稱", "在直轄市為直轄市法規", "自治條例在縣稱縣規章", "自治條例在鄉稱鄉規程"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:31:19+00:00", "source_pdf_sha1": "6a91a5eb9855", "answer_pdf_sha1": "413126103154", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "512", "s": "0202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "法學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "經建行政"}'::jsonb, NULL)
